# --- list_dir ---


def test_list_dir_entries(backend: MemoryBackend):
    backend.make_dir(P('/d'), parents=False)
    backend.make_dir(P('/d/sub'), parents=False)
    put(backend, '/d/a.txt', b'12345')

    entries = {(e.name, e.is_dir, e.size) for e in backend.list_dir(P('/d'))}
    assert entries == {('sub', True, 0), ('a.txt', False, 5)}


def test_list_dir_on_file_raises(backend: MemoryBackend):
    put(backend, '/a.txt')
    with pytest.raises(NotADirectoryError):
        for _ in backend.list_dir(P('/a.txt')):
            pass


def test_list_dir_missing_raises(backend: MemoryBackend):
    with pytest.raises(PathNotFoundError):
        for _ in backend.list_dir(P('/nope')):
            pass


def test_list_dir_tolerates_delete_during_iteration(backend: MemoryBackend):
    backend.make_dir(P('/d'), parents=False)
    for name in ('a', 'b', 'c'):
        put(backend, f'/d/{name}')

    for entry in backend.list_dir(P('/d')):
        backend.delete(P('/d') / entry.name)

    assert list(backend.list_dir(P('/d'))) == []


# --- stat ---


def test_stat_file(backend: MemoryBackend):
    put(backend, '/a.txt', b'12345')
    props = backend.stat(P('/a.txt'))
    assert props.kind == 'file'
    assert props.size == 5
    assert props.created.tzinfo is not None
    assert props.modified.tzinfo is not None


def test_stat_directory_size_is_zero(backend: MemoryBackend):
    backend.make_dir(P('/d'), parents=False)
    put(backend, '/d/a.txt', b'12345')
    props = backend.stat(P('/d'))
    assert props.kind == 'directory'
    assert props.size == 0


def test_append_updates_modified_preserves_created(backend: MemoryBackend):
    put(backend, '/a.txt', b'x')
    before = backend.stat(P('/a.txt'))
    put(backend, '/a.txt', b'y', mode='a')
    after = backend.stat(P('/a.txt'))
    assert after.created == before.created
    assert after.modified >= before.modified


