def test_move_file(backend: MemoryBackend):
    put(backend, '/src.txt', b'payload')
    backend.move(P('/src.txt'), P('/dst.txt'))
    assert backend.read(P('/dst.txt')) == b'payload'
    assert not backend.exists(P('/src.txt'))


def test_copy_file_is_independent(backend: MemoryBackend):
    put(backend, '/src.txt', b'payload')
    backend.copy(P('/src.txt'), P('/dst.txt'))
    assert backend.read(P('/dst.txt')) == b'payload'

    # mutating the copy must not touch the original (no buffer aliasing)
    put(backend, '/dst.txt', b' more', mode='a')
    assert backend.read(P('/src.txt')) == b'payload'


def test_delete_tree_removes_everything(backend: MemoryBackend):
    backend.make_dir(P('/d/sub'), parents=True)
    put(backend, '/d/a.txt', b'x')
    put(backend, '/d/sub/b.txt', b'y')

    backend.delete_tree(P('/d'))

    for path in ('/d', '/d/sub', '/d/a.txt', '/d/sub/b.txt'):
        assert not backend.exists(P(path))
    assert backend.exists(P('/'))
